logger = logging.getLogger(__name__)


class RabbitMQConfig:
    """Configuration for RabbitMQ connection."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'guest',
        password: str = 'guest',
        virtual_host: str = '/',
        heartbeat: int = 600,
        connection_attempts: int = 3,
        retry_delay: int = 5
    ):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.virtual_host = virtual_host
        self.heartbeat = heartbeat
        self.connection_attempts = connection_attempts
        self.retry_delay = retry_delay

    def get_connection_parameters(self) -> pika.ConnectionParameters:
        credentials = pika.PlainCredentials(self.username, self.password)
        return pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            heartbeat=self.heartbeat,
            connection_attempts=self.connection_attempts,
            retry_delay=self.retry_delay
        )


class TaskMessage:
    """Represents a task message in the distributed system."""

    def __init__(
        self,
        task_type: str,
        payload: dict,
        priority: int = 0,
        task_id: Optional[str] = None
    ):
        self.task_id = task_id or str(uuid.uuid4())
        self.task_type = task_type
        self.payload = payload
        self.priority = priority
        self.created_at = datetime.utcnow().isoformat()

    def to_json(self) -> str:
        return json.dumps({
            'task_id': self.task_id,
            'task_type': self.task_type,
            'payload': self.payload,
            'priority': self.priority,
            'created_at': self.created_at
        })

    @classmethod
    def from_json(cls, json_str: str) -> 'TaskMessage':
        data = json.loads(json_str)
        msg = cls(
            task_type=data['task_type'],
            payload=data['payload'],
            priority=data.get('priority', 0),
            task_id=data.get('task_id')
        )
        msg.created_at = data.get('created_at', msg.created_at)
        return msg

    def __repr__(self):
        return (
            f"TaskMessage(id={self.task_id}, type={self.task_type}, "
            f"priority={self.priority})"
        )


class TaskPublisher:
    """Publishes task messages to RabbitMQ queues."""

    def __init__(self, config: Optional[RabbitMQConfig] = None):
        self.config = config or RabbitMQConfig()
        self.connection = None
        self.channel = None

    def connect(self):
        """Establish connection to RabbitMQ."""
        try:
            params = self.config.get_connection_parameters()
            self.connection = pika.BlockingConnection(params)
            self.channel = self.connection.channel()
            logger.info(
                f"Publisher connected to RabbitMQ at "
                f"{self.config.host}:{self.config.port}"
            )
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise

    def setup_queue(
        self,
        queue_name: str,
        durable: bool = True,
        exchange_name: str = '',
        exchange_type: str = 'direct',
        routing_key: Optional[str] = None,
        dead_letter_exchange: Optional[str] = None,
        message_ttl: Optional[int] = None
    ):
        """Declare queue and optional exchange with dead letter support."""
        if not self.channel:
            self.connect()

        arguments = {}
        if dead_letter_exchange:
            # Set up dead letter exchange and queue
            dlx_queue = f"{queue_name}_dlq"
            self.channel.exchange_declare(
                exchange=dead_letter_exchange,
                exchange_type='direct',
                durable=True
            )
            self.channel.queue_declare(
                queue=dlx_queue,
                durable=True
            )
            self.channel.queue_bind(
                queue=dlx_queue,
                exchange=dead_letter_exchange,
                routing_key=queue_name
            )
            arguments['x-dead-letter-exchange'] = dead_letter_exchange
            arguments['x-dead-letter-routing-key'] = queue_name

        if message_ttl:
            arguments['x-message-ttl'] = message_ttl

        # Declare the main exchange if specified
        if exchange_name:
            self.channel.exchange_declare(
                exchange=exchange_name,
                exchange_type=exchange_type,
                durable=True
            )

        # Declare the main queue
        self.channel.queue_declare(
            queue=queue_name,
            durable=durable,
            arguments=arguments if arguments else None
        )

        # Bind queue to exchange if specified
        if exchange_name:
            bind_key = routing_key or queue_name
            self.channel.queue_bind(
                queue=queue_name,
                exchange=exchange_name,
                routing_key=bind_key
            )

        logger.info(f"Queue '{queue_name}' declared and ready")

    def publish(
        self,
        task: TaskMessage,
        queue_name: str = 'task_queue',
        exchange_name: str = '',
        routing_key: Optional[str] = None,
        persistent: bool = True,
        expiration: Optional[str] = None
    ) -> bool:
        """Publish a task message to the specified queue."""
        if not self.channel:
            self.connect()

        try:
            properties = pika.BasicProperties(
                delivery_mode=2 if persistent else 1,
                content_type='application/json',
                message_id=task.task_id,
                timestamp=int(time.time()),
                priority=task.priority,
                headers={
                    'task_type': task.task_type,
                    'created_at': task.created_at
                }
            )

            if expiration:
                properties.expiration = expiration

            rk = routing_key or queue_name
            self.channel.basic_publish(
                exchange=exchange_name,
                routing_key=rk,
                body=task.to_json(),
                properties=properties
            )

            logger.info(
                f"Published task {task.task_id} (type={task.task_type}) "
                f"to queue '{queue_name}'"
            )
            return True

        except pika.exceptions.AMQPError as e:
            logger.error(f"Failed to publish task {task.task_id}: {e}")
            return False

    def publish_batch(
        self,
        tasks: list,
        queue_name: str = 'task_queue',
        exchange_name: str = '',
        routing_key: Optional[str] = None
    ) -> int:
        """Publish multiple task messages. Returns count of successfully published."""
        success_count = 0
        for task in tasks:
            if self.publish(task, queue_name, exchange_name, routing_key):
                success_count += 1
        logger.info(
            f"Batch publish complete: {success_count}/{len(tasks)} tasks published"
        )
        return success_count

    def close(self):
        """Close the connection."""
        if self.connection and not self.connection.is_closed:
            self.connection.close()
            logger.info("Publisher connection closed")


class TaskConsumer:
    """Consumes and processes task messages from RabbitMQ queues."""

    def __init__(
        self,
        config: Optional[RabbitMQConfig] = None,
        prefetch_count: int = 1
    ):
        self.config = config or RabbitMQConfig()
        self.connection = None
        self.channel = None
        self.prefetch_count = prefetch_count
        self._task_handlers: dict[str, Callable] = {}
        self._default_handler: Optional[Callable] = None
        self._consuming = False

    def connect(self):
        """Establish connection to RabbitMQ."""
        try:
            params = self.config.get_connection_parameters()
            self.connection = pika.BlockingConnection(params)
            self.channel = self.connection.channel()
            self.channel.basic_qos(prefetch_count=self.prefetch_count)
            logger.info(
                f"Consumer connected to RabbitMQ at "
                f"{self.config.host}:{self.config.port}"
            )
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise

    def register_handler(
        self,
        task_type: str,
        handler: Callable[[TaskMessage], bool]
    ):
        """Register a handler function for a specific task type."""
        self._task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def set_default_handler(self, handler: Callable[[TaskMessage], bool]):
        """Set a default handler for unregistered task types."""
        self._default_handler = handler
        logger.info("Default task handler set")

    def _on_message(self, channel, method, properties, body):
        """Internal callback for processing received messages."""
        task = None
        try:
            task = TaskMessage.from_json(body.decode('utf-8'))
            logger.info(
                f"Received task {task.task_id} (type={task.task_type})"
            )

            # Find appropriate handler
            handler = self._task_handlers.get(task.task_type)
            if handler is None:
                handler = self._default_handler

            if handler is None:
                logger.warning(
                    f"No handler registered for task type: {task.task_type}. "
                    f"Rejecting message."
                )
                channel.basic_nack(
                    delivery_tag=method.delivery_tag, requeue=False
                )
                return

            # Execute handler
            start_time = time.time()
            success = handler(task)
            elapsed = time.time() - start_time

            if success:
                channel.basic_ack(delivery_tag=method.delivery_tag)
                logger.info(
                    f"Task {task.task_id} completed successfully "
                    f"in {elapsed:.3f}s"
                )
            else:
                channel.basic_nack(
                    delivery_tag=method.delivery_tag, requeue=True
                )
                logger.warning(
                    f"Task {task.task_id} failed, requeued"
                )

        except json.JSONDecodeError as e:
            logger.error(f"Invalid JSON in message body: {e}")
            channel.basic_nack(
                delivery_tag=method.delivery_tag, requeue=False
            )
        except Exception as e:
            task_id = task.task_id if task else 'unknown'
            logger.error(
                f"Error processing task {task_id}: {e}", exc_info=True
            )
            channel.basic_nack(
                delivery_tag=method.delivery_tag, requeue=False
            )

    def consume(
        self,
        queue_name: str = 'task_queue',
        auto_ack: bool = False
    ):
        """Start consuming messages from the specified queue."""
        if not self.channel:
            self.connect()

        # Ensure queue exists
        self.channel.queue_declare(queue=queue_name, durable=True, passive=True)

        self.channel.basic_consume(
            queue=queue_name,
            on_message_callback=self._on_message,
            auto_ack=auto_ack
        )

        self._consuming = True
        logger.info(f"Consumer started, waiting for tasks on '{queue_name}'...")

        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            self.stop()

    def stop(self):
        """Stop consuming and close connection."""
        self._consuming = False
        if self.channel:
            self.channel.stop_consuming()
        if self.connection and not self.connection.is_closed:
            self.connection.close()
        logger.info("Consumer stopped and connection closed")


