def run_publisher_demo():
    """Demonstrate the publisher by sending sample tasks."""
    config = RabbitMQConfig()
    publisher = TaskPublisher(config)

    try:
        publisher.connect()

        # Setup queue with dead letter exchange
        publisher.setup_queue(
            queue_name='task_queue',
            durable=True,
            dead_letter_exchange='dlx_exchange',
            message_ttl=300000  # 5 minutes
        )

        # Publish individual tasks
        tasks = [
            TaskMessage(
                task_type='email',
                payload={
                    'recipient': 'user@example.com',
                    'subject': 'Welcome!',
                    'body': 'Welcome to our platform.'
                },
                priority=1
            ),
            TaskMessage(
                task_type='data_processing',
                payload={
                    'dataset': 'sales_2024_q1',
                    'operation': 'aggregate',
                    'output_format': 'csv'
                },
                priority=2
            ),
            TaskMessage(
                task_type='notification',
                payload={
                    'user_id': 'usr_12345',
                    'message': 'Your report is ready for download.',
                    'channel': 'push'
                },
                priority=0
            ),
            TaskMessage(
                task_type='email',
                payload={
                    'recipient': 'admin@example.com',
                    'subject': 'Daily Report',
                    'body': 'Please find attached the daily report.'
                },
                priority=1
            ),
            TaskMessage(
                task_type='cleanup',
                payload={
                    'target': 'temp_files',
                    'older_than_days': 7
                },
                priority=0
            ),
        ]

        # Publish individually
        for task in tasks[:2]:
            publisher.publish(task, queue_name='task_queue')
            time.sleep(0.1)

        # Publish batch
        publisher.publish_batch(tasks[2:], queue_name='task_queue')

        logger.info("All demo tasks published successfully!")

    except Exception as e:
        logger.error(f"Publisher demo failed: {e}")
    finally:
        publisher.close()


def run_consumer_demo():
    """Demonstrate the consumer by processing tasks from the queue."""
    config = RabbitMQConfig()
    consumer = TaskConsumer(config, prefetch_count=1)

    # Register task type handlers
    consumer.register_handler('email', handle_email_task)
    consumer.register_handler('data_processing', handle_data_processing_task)
    consumer.register_handler('notification', handle_notification_task)
    consumer.set_default_handler(default_task_handler)

    try:
        consumer.connect()

        # Ensure queue exists before consuming
        consumer.channel.queue_declare(queue='task_queue', durable=True)

        consumer.consume(queue_name='task_queue')
    except pika.exceptions.AMQPConnectionError:
        logger.error(
            "Could not connect to RabbitMQ. "
            "Make sure RabbitMQ is running on localhost:5672"
        )
    except Exception as e:
        logger.error(f"Consumer demo failed: {e}")
    finally:
        consumer.stop()


def main():
    parser = argparse.ArgumentParser(
        description='Distributed Task Processing System with RabbitMQ'
    )
    parser.add_argument(
        'mode',
        choices=['publish', 'consume', 'both'],
        help='Run as publisher, consumer, or both (publish then consume)'
    )
    parser.add_argument(
        '--host', default='localhost',
        help='RabbitMQ host (default: localhost)'
    )
    parser.add_argument(
        '--port', type=int, default=5672,
        help='RabbitMQ port (default: 5672)'
    )

    args = parser.parse_args()

    if args.mode == 'publish':
        logger.info("Starting publisher demo...")
        run_publisher_demo()
    elif args.mode == 'consume':
        logger.info("Starting consumer demo...")
        run_consumer_demo()
    elif args.mode == 'both':
        logger.info("Starting publisher demo...")
        run_publisher_demo()
        logger.info("\nStarting consumer demo (Ctrl+C to stop)...")
        run_consumer_demo()


if __name__ == '__main__':
    main()